class Mutex {
  constructor() {
    this._locked = false;
    this._queue = [];
  }

  lock() {
    return new Promise((resolve) => {
      if (!this._locked) {
        this._locked = true;
        resolve(this._unlock.bind(this));
      } else {
        this._queue.push(resolve);
      }
    });
  }

  _unlock() {
    if (this._queue.length > 0) {
      const next = this._queue.shift();
      next(this._unlock.bind(this));
    } else {
      this._locked = false;
    }
  }
}

const mutex = new Mutex();

// ----------------------------------------------------------------------
